head.script:
// LoginDTO loginDTO = LoginUtil.getLoginDTO(request);
scwin.userHomeClsCd = $c.data.getMemInfo("userHomeClsCd") // 사용자소속구분코드
scwin.sysAdminYn = $c.data.getMemInfo("sysAdminYn") + ""

// String currentDate = DDate.getDate("");	// 현재일자를 구한다.
// DDate sDate = new DDate();
// String strFromDate = sDate.getDate("");         // 현재년월일을 구한다.
// strFromDate = strFromDate.substring(0, 6) + "01";
// String strLastDate = Integer.toString(sDate.getLastDate(strFromDate));
// String strToDate = strFromDate.substring(0, 6) + strLastDate;

scwin.strFromDate = $c.date.getServerDateTime("yyyyMM") + "01";
scwin.strLastDate = $c.date.getLastDateOfMonth(scwin.strFromDate);
scwin.strToDate = scwin.strFromDate.substring(0, 6) + scwin.strLastDate;

scwin.pos_ctrt = 0;
scwin.g_sUserId = $c.data.getMemInfo("userId");
scwin.g_sUserNm = $c.data.getMemInfo("userNm");
scwin.g_sAcctDeptCd = $c.data.getMemInfo("acctDeptCd");
scwin.g_sAcctDeptNm = $c.data.getMemInfo("acctDeptNm");
scwin.g_sEmpNo = $c.data.getMemInfo("epId");
scwin.currentDate = $c.date.getServerDateTime("yyyyMMdd");

scwin.manager = "";
scwin.managerYn = ""; //관리자 여부


// 화면
scwin.onpageload = function () {
	const codeOptions = [
        { grpCd: "ZZ021", compID: "lc_apprvStsCd", opt: { "range": "2,1" } } // 상태
    ]
    $c.data.setCommonCode(codeOptions)
};


//-------------------------------------------------------------------------
// 화면로딩시 UDC 호출
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function () {
    scwin.f_ContentsDisable();
    $c.gus.cfDisableBtn([btn_Create2, btn_Copy2, btn_Update2, btn_Cancel2, btn_Save2, btn_Delete2, btn_Aprv2]);

    // f_createHeader();
    ed_ctrtStDt.setValue(scwin.strFromDate);
    ed_ctrtEndDt.setValue(scwin.strToDate);

    /* const codeOptions = [
        { grpCd: "ZZ021", compID: "lc_apprvStsCd,gr_ctrt:apprvStsCd" } // 상태
    ]
    $c.data.setCommonCode(codeOptions) */
};

//-------------------------------------------------------------------------
// 공통코드가 셋팅이 되고 scwin.ondataload 이벤트가 호출
//-------------------------------------------------------------------------
scwin.ondataload = function() { 
    lc_apprvStsCd.addItem("99", "회수")
};

// 귀속부서 공통팝업 
scwin.openAcctDeptPopup = function (udcObj, codeInput, nameInput, codeVal, nameVal) {

    var pWhere = ed_ctrtStDt.getValue().substring(0, 4) + ",,,,,,,,," + "000";

    udcObj.cfCommonPopUp(
        function(ret){
            scwin.commonAcctDeptCallback(codeInput, nameInput, ret);
        },
        codeVal,
        nameVal,
        "T",
        null, null, null, null,
        pWhere,
        "450",
        "500",
        null, null, null,
        "F",
        null,
        null
    );
};

// 귀속부서 공통 콜백
scwin.commonAcctDeptCallback = function(codeInput, nameInput, ret){

    if (!ret || ret[0] == "N/A") {
        return;
    }

    codeInput.setValue(ret[0]);
    nameInput.setValue(ret[1]);
};

// 클릭
scwin.udc_acctDeptCd_onclickEvent = function () {
    scwin.openAcctDeptPopup(
        udc_acctDeptCd,
        ed_acctDeptCd,
        ed_acctDeptNm,
        ed_acctDeptCd.getValue(),
        ed_acctDeptNm.getValue()
    );
};

// blur
scwin.udc_acctDeptCd_onblurCodeEvent = function () {
    scwin.openAcctDeptPopup(
        udc_acctDeptCd,
        ed_acctDeptCd,
        ed_acctDeptNm,
        ed_acctDeptCd.getValue(),
        ""
    );
};

// name 변경
scwin.udc_acctDeptCd_onviewchangeNameEvent = function () {
    scwin.openAcctDeptPopup(
        udc_acctDeptCd,
        ed_acctDeptCd,
        ed_acctDeptNm,
        "",
        ed_acctDeptNm.getValue()
    );
};

// 클릭
scwin.udc_acctDeptCd2_onclickEvent = function () {
    scwin.openAcctDeptPopup(
        udc_acctDeptCd2,
        ed_acctDeptCd2,
        ed_acctDeptNm2,
        ed_acctDeptCd2.getValue(),
        ed_acctDeptNm2.getValue()
    );
};

// blur
scwin.udc_acctDeptCd2_onblurCodeEvent = function () {
    scwin.openAcctDeptPopup(
        udc_acctDeptCd2,
        ed_acctDeptCd2,
        ed_acctDeptNm2,
        ed_acctDeptCd2.getValue(),
        ""
    );
};

// name 변경
scwin.udc_acctDeptCd2_onviewchangeNameEvent = function () {
    scwin.openAcctDeptPopup(
        udc_acctDeptCd2,
        ed_acctDeptCd2,
        ed_acctDeptNm2,
        "",
        ed_acctDeptNm2.getValue()
    );
};

// 주소 우편번호 검색
scwin.f_openZipPopUp = async function (e) {
    // var rtnList = new Array();
    // var popupResult = window.showModalDialog("/cm/zz/newzipcodePopup.jsp", "",
    //     "dialogHeight:400px;dialogWidth:530px;center:yes;scroll:no;status:no;help:no");

    var url = "/ui/cm/zz/newzipcodePopup.xml";

    let opts = {
        width: "530px"
        , height: "400px"
        , dialogleft: "100px"
        , scrollbars: "no"
        , status: "no"
        , help: "no"
        , style: "center"
    };

    var popupResult = await $c.win.openPopup(url, opts);

    // Modal Dialog를 리턴값 없이 닫을 경우에 대비해
    if (popupResult != null) {
        if (popupResult[0] == "N/A") return;
        //        		zip.Text = popupResult.zip;
        ed_clntAddr.setValue(popupResult.addr1)
    } else {
        //        		zip.Text = "";
        ed_clntAddr.setValue("")
    }

};

// 사업자번호 UDC
scwin.udc_clntCrn_onclickEvent = function (gbn) {
    // rtnList = cfCommonPopUp('retrieveCrnInfo', '', '', "F", null, null, null, "3,4,5,6,7,8,9,10", null, null, null, null, null, null, null, null); //  사업자등록번호

    udc_clntCrn.setSelectId("retrieveCrnInfo")
    udc_clntCrn.cfCommonPopUp(
        gbn == "1" ? scwin.udc_clntCrn_srch_callBackFunc : scwin.udc_clntCrn_form_callBackFunc
        , ''
        , ''
        , "F"
        , null
        , null
        , null
        , "3,4,5,6,7,8,9,10"
        , null
        , null
        , null
        , null
        , null
        , null
        , null
        , null); //  사업자등록번호
};

// 사업자등록정보 공통팝업
scwin.f_openCrnPopUp = function (_schGb) {
    scwin.udc_clntCrn_onclickEvent(_schGb)
}

////////////////////////////////////////////////////////
// 품명 공통팝업 그리드 콜백
////////////////////////////////////////////////////////
scwin.udc_clntCrn_srch_callBackFunc = function (ret) {
    if (ret[0] == "N/A") {
      return;
    }
    ed_clntCrn.setValue(ret[0])	// 사업자등록번호
};

scwin.udc_clntCrn_form_callBackFunc = function (ret) {
    if (ret[0] == "N/A") {
      return;
    }
    ed_clntCrn2.setValue(ret[0])	// 사업자등록번호
};

// 조회조건 초기화
scwin.f_FieldClear = function (e) {
    $c.gus.cfInitObjects(tbl_search)
};

// 조회
scwin.f_Retrieve = async function (e) {
    scwin.f_ContentsDisable();
    let ret = await $c.gus.cfValidate([ed_ctrtStDt,ed_ctrtEndDt]);
    if (!ret) {
        return false;
    }

    // 조회일자 from ~ to 체크	
    if (!$c.gus.cfIsAfterDate(ed_ctrtStDt.getValue(), ed_ctrtEndDt.getValue())) {
    	$c.gus.cfAlertMsg(MSG_CM_ERR_039); // "시작일자가 종료일자 이전이어야 합니다."
    	return;
    }

    // tr_retrieve.Post(); 
    $c.sbm.execute(sbm_retrieve)
};

//-------------------------------------------------------------------------
// 그리드 사용여부 데이터 포맷처리
//-------------------------------------------------------------------------
scwin.displayCtrtApprDt = function (data) {
    return $c.gus.decode(data, "", "N", "Y");
};

// ctrt(계약정보) 조회 완료
scwin.sbm_retrieve_submitdone = function (e) {
    // 조회 성공시
    if (e.responseJSON.resultDataSet[0].Code == 0) {
        //gr_ctrt.checkAll('chk', false)   
        if (ds_ctrt.getRowCount() == 0) {
            scwin.f_ContentsDisable()
            $c.gus.cfDisableBtn([btn_Update2, btn_Cancel2, btn_Save2, btn_Aprv2, btn_Copy2, btn_Delete2])
            $c.win.alert("조회된 데이터가 없습니다.")
        } else {
            ds_ctrt.setRowPosition(0)
            gr_ctrt.setFocusedCell(0, 0)

        }
		 // 그리드 조회건수
		 tbx_totalRows.setValue($c.gus.cfInsertComma(ds_ctrt.getRowCount()))
    }
};

scwin.rowPos = 0;
// 계약정보 행 변경시
scwin.ds_ctrt_onrowpositionchange = function (info) {
	scwin.rowPos = info.newRowIndex ?? scwin.rowPos;
	scwin.f_ContentsDisable()
	$c.gus.cfDisableBtn([btn_Cancel2, btn_Save2])
};

